module.exports = {
  preset: 'ts-jest',
  testEnvironment: 'node',
  testMatch: ['**/tests/**/*.test.ts'],
  moduleFileExtensions: ['ts', 'js', 'json'],
  verbose: true
};

import express from 'express';
import path from 'path';

const app = express();
app.use(express.json());

const publicDir = path.join(__dirname, 'public');

// Serve the test page explicitly at root
app.get('/', (_req, res) => {
  res.sendFile(path.join(publicDir, 'index.html'));
});

// Static assets (including compiled tailwind.css)
app.use(express.static(publicDir));

app.get('/healthz', (_req, res) => res.json({ status: 'ok' }));

export default app;

import app from './app';

const port = Number(process.env.PORT) || 4445;

app.listen(port, () => {
  console.log(`Server running on http://localhost:${port}`);
});

import request from 'supertest';
import app from '../src/app';

describe('Express server with Tailwind', () => {
  it('serves index.html with Tailwind link and test element', async () => {
    const res = await request(app).get('/');
    expect(res.status).toBe(200);
    expect(res.text).toContain('Tailwind OK');
    expect(res.text).toContain('/tailwind.css');
    expect(res.text).toContain('bg-blue-600');
  });
});
